import { PlusCircleIcon, Search } from "lucide-react";
import { useCallback, useState } from "react";

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";

import { useRoleEditContext } from "../context";

import { PermissionItem } from "./permission-item";
import { ResourcePicker } from "./resource-picker";

export const AssignedRolePermissions = () => {
  const {
    permissions,
    addPermission,
    removePermission,
    updatePermissionModifier,
    togglePermissionExpanded,
  } = useRoleEditContext();

  const [searchQuery, setSearchQuery] = useState("");
  const filteredPermissions = permissions.filter((p) =>
    p.resource.toLowerCase().includes(searchQuery.toLowerCase()),
  );

  const assignedResourceIds = permissions.map((p) => p.resource);
  const handleAddPermissions = useCallback(
    (resourceIds: string[]) => {
      for (const id of resourceIds) addPermission(id);
    },
    [addPermission],
  );

  return (
    <div className="flex h-full flex-col lg:col-span-5">
      <Card className="bg-sidebar flex h-full max-h-screen flex-col lg:sticky lg:top-6">
        <div className="z-10 rounded-t-xl px-6">
          <div className="mb-1 flex items-center justify-between">
            <h2 className="text-lg font-semibold">Permissions</h2>
            <div className="flex items-center gap-2">
              <Badge
                variant="outline"
                className="bg-primary/10 text-primary border-0"
              >
                {permissions.length} Assigned
              </Badge>
              <ResourcePicker
                selectedResources={assignedResourceIds}
                onSelect={handleAddPermissions}
                trigger={
                  <Button
                    type="button"
                    size="icon-sm"
                    variant="ghost"
                    className="gap-1"
                  >
                    <PlusCircleIcon className="size-4" />
                  </Button>
                }
              />
            </div>
          </div>
          <p className="text-muted-foreground text-sm">
            Assign granular capabilities to this role.
          </p>

          {permissions.length > 3 && (
            <div className="relative mt-3">
              <Search className="text-muted-foreground absolute top-2.5 left-3 size-4" />
              <Input
                type="text"
                placeholder="Search assigned permissions..."
                name="search_assigned_permissions"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
          )}
        </div>

        <CardContent className="flex-1 overflow-hidden p-0">
          <ScrollArea className="h-full">
            <div className="space-y-3 px-6">
              {filteredPermissions.length === 0 ? (
                <div className="text-muted-foreground py-8 text-center">
                  {permissions.length === 0
                    ? "No permissions assigned yet."
                    : "No permissions match your search."}
                </div>
              ) : (
                filteredPermissions.map((permission) => (
                  <PermissionItem
                    key={permission.resource}
                    permission={permission}
                    onToggleExpand={togglePermissionExpanded}
                    onRemove={removePermission}
                    onModifierChange={updatePermissionModifier}
                  />
                ))
              )}
            </div>
          </ScrollArea>
        </CardContent>
      </Card>
    </div>
  );
};

import { useContentList, useFastSchema } from "fastschema/react";
import { Plus, Search, UserPlus } from "lucide-react";
import { useCallback, useMemo, useRef, useState } from "react";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Loading } from "@/components/fsui/fscommon";
import { FsDialog } from "@/components/fsui/fscommon/dialog";
import {
  RelationPickerList,
  type RelationPickerListRef,
} from "@/components/fsui/fspage-content-list/relation-picker-list";

import { useRoleEditContext } from "../context";

import { UserItem } from "./user-item";

import type { Entity, Filter, FilterObject, User } from "fastschema";

export const AssignedRoleUsers = () => {
  const { initialData } = useRoleEditContext();
  const { fastschema } = useFastSchema();
  const roleId = initialData?.id;

  const [searchQuery, setSearchQuery] = useState("");
  const [pagination, setPagination] = useState({ page: 1, limit: 5 });
  const [dialogOpen, setDialogOpen] = useState(false);
  const [attachableUsers, setAttachableUsers] = useState<Entity[]>([]);
  const [isMutating, setIsMutating] = useState(false);
  const availableUsersRef = useRef<RelationPickerListRef>(null);

  const connectedFilter = useMemo<Filter>(() => {
    const filter: Filter = {};
    if (roleId) {
      filter["roles"] = {
        $eq: roleId,
      };
    }
    if (searchQuery) {
      filter.$or = [
        { username: { $like: `%${searchQuery}%` } },
        { email: { $like: `%${searchQuery}%` } },
        { first_name: { $like: `%${searchQuery}%` } },
        { last_name: { $like: `%${searchQuery}%` } },
      ];
    }
    return filter;
  }, [roleId, searchQuery]);

  const availableUsersFilter = useMemo<Filter>(() => {
    if (!roleId) return {} as FilterObject;
    return {
      "roles.id": {
        $neq: roleId,
      },
    };
  }, [roleId]);

  const { result, isLoading, isFetching, reFetch } = useContentList({
    schemaName: "user",
    filter: connectedFilter,
    page: pagination.page,
    limit: pagination.limit,
  });

  const users = (result?.items || []) as User[];
  const totalUsers = result?.total || 0;
  const totalPages = result?.last_page || 1;

  const handleRemoveUser = useCallback(
    async (userId: number | string) => {
      if (!roleId) return;

      setIsMutating(true);
      try {
        const roleSchema = fastschema.schema("role");
        await roleSchema?.update(roleId, {
          users: {
            $clear: [{ id: userId as number }],
          },
        });
        reFetch();
        toast.success("User detached successfully");
      } catch (error) {
        toast.error(`Failed to detach user: ${(error as Error).message}`);
      } finally {
        setIsMutating(false);
      }
    },
    [roleId, fastschema, reFetch],
  );

  const handleAttachUsers = useCallback(async () => {
    if (!roleId || attachableUsers.length === 0) return;

    setIsMutating(true);
    try {
      const roleSchema = fastschema.schema("role");
      await roleSchema?.update(roleId, {
        users: {
          $add: attachableUsers.map((u) => ({ id: u.id as number })),
        },
      });
      setAttachableUsers([]);
      setDialogOpen(false);
      reFetch();
      toast.success(`Successfully attached ${attachableUsers.length} user(s)`);
    } catch (error) {
      toast.error(`Failed to attach users: ${(error as Error).message}`);
    } finally {
      setIsMutating(false);
    }
  }, [roleId, attachableUsers, fastschema, reFetch]);

  const handleDialogClose = useCallback(() => {
    setDialogOpen(false);
    setAttachableUsers([]);
  }, []);

  if (!roleId) {
    return (
      <section className="space-y-4">
        <div>
          <h3 className="text-lg font-semibold tracking-tight">
            Assigned Users
          </h3>
          <p className="text-muted-foreground text-sm">
            Manage users who are directly assigned to this role.
          </p>
        </div>
        <Card className="p-0">
          <CardContent className="p-8 text-center">
            <div className="text-muted-foreground p-8 text-center">
              Save the role first to attach users.
            </div>
          </CardContent>
        </Card>
      </section>
    );
  }

  return (
    <section className="space-y-4">
      <div>
        <h3 className="text-lg font-semibold tracking-tight">Assigned Users</h3>
        <p className="text-muted-foreground text-sm">
          Manage users who are directly assigned to this role.
        </p>
      </div>

      <Card className="p-0">
        <CardContent className="p-0">
          {/* Search and Add User Header */}
          <div className="border-border bg-muted/20 flex flex-col gap-3 border-b p-4 sm:flex-row">
            <div className="relative flex-1">
              <Search className="text-muted-foreground absolute top-2.5 left-3 size-4" />
              <Input
                type="text"
                name="search_assigned_users"
                placeholder="Search assigned users..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-10"
              />
            </div>
            <FsDialog
              open={dialogOpen}
              onOpenChange={(val) => {
                setDialogOpen(val);
                if (!val) {
                  handleDialogClose();
                }
              }}
              hideFooter
              trigger={
                <Button
                  type="button"
                  className="gap-2"
                  size="sm"
                >
                  <Plus className="size-4" />
                  Add User
                </Button>
              }
              title="Add Users to Role"
            >
              <div className="flex h-[400px] flex-col">
                <RelationPickerList
                  ref={availableUsersRef}
                  schemaName="user"
                  label={<div className="font-medium">Available Users</div>}
                  multiSelection={true}
                  initialFilter={availableUsersFilter}
                  onSelectionChange={setAttachableUsers}
                  actions={
                    <Button
                      size="sm"
                      className="gap-2"
                      onClick={handleAttachUsers}
                      disabled={attachableUsers.length === 0 || isMutating}
                    >
                      <UserPlus className="size-4" />
                      Attach ({attachableUsers.length})
                    </Button>
                  }
                />
              </div>
            </FsDialog>
          </div>

          <div className={isFetching ? "pointer-events-none opacity-50" : ""}>
            {isLoading ? (
              <div className="p-8">
                <Loading />
              </div>
            ) : users.length === 0 ? (
              <div className="text-muted-foreground p-8 text-center">
                No users assigned to this role.
              </div>
            ) : (
              <ScrollArea className="max-h-[300px]">
                <div className="divide-border divide-y">
                  {users.map((user) => (
                    <UserItem
                      key={user.id}
                      user={user}
                      onRemove={handleRemoveUser}
                    />
                  ))}
                </div>
              </ScrollArea>
            )}
          </div>

          {totalUsers > 0 && (
            <div className="bg-muted/5 border-border flex items-center justify-between border-t p-3">
              <span className="text-muted-foreground text-xs">
                Showing {users.length} of {totalUsers} users
              </span>
              <div className="flex items-center gap-2">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={pagination.page <= 1}
                  onClick={() =>
                    setPagination((prev) => ({ ...prev, page: prev.page - 1 }))
                  }
                >
                  Previous
                </Button>
                <span className="text-muted-foreground text-xs">
                  Page {pagination.page} of {totalPages}
                </span>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={pagination.page >= totalPages}
                  onClick={() =>
                    setPagination((prev) => ({ ...prev, page: prev.page + 1 }))
                  }
                >
                  Next
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>
    </section>
  );
};

import { Info } from "lucide-react";

import { FieldCodeInput } from "@/components/fsui/fscommon/field-code-input";

import { useRoleEditForm } from "../context";

export const RoleGlobalRuleField = () => {
  const form = useRoleEditForm();

  return (
    <section className="space-y-4">
      <form.Field
        name="rule"
        children={(field) => {
          const isInvalid =
            field.state.meta.isTouched && !field.state.meta.isValid;
          return (
            <div className="space-y-2">
              <FieldCodeInput
                isInvalid={isInvalid}
                name="global_rule.js"
                label={
                  <div>
                    <h3 className="text-lg font-semibold tracking-tight">
                      Global Logic
                    </h3>
                    <p className="text-muted-foreground text-sm font-normal">
                      Apply logic that affects all permissions within this role.
                    </p>
                  </div>
                }
                value={(field.state.value as string) ?? ""}
                errors={field.state.meta.errors}
                onChange={(value) => field.handleChange(value)}
                onBlur={field.handleBlur}
              />
              <div className="text-muted-foreground flex items-center gap-1 px-1 text-xs">
                <Info className="size-3.5" />
                Supports{" "}
                <p>
                  <a
                    href="https://github.com/expr-lang/expr"
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    expr
                  </a>{" "}
                  syntax for contextual validation.
                </p>
              </div>
            </div>
          );
        }}
      />
    </section>
  );
};

import { Code, EyeOffIcon, XCircle, Shield } from "lucide-react";
import { useCallback } from "react";

import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

import type { PermissionState } from "../context";

export interface PermissionItemProps {
  permission: PermissionState;
  onToggleExpand: (resource: string) => void;
  onRemove: (resource: string) => void;
  onModifierChange: (resource: string, modifier: string | null) => void;
}

const getPermissionIconColor = (resource: string): string => {
  if (resource.includes("user")) {
    return "bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400";
  }
  if (resource.includes("content") || resource.includes("publish")) {
    return "bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400";
  }
  if (resource.includes("system") || resource.includes("log")) {
    return "bg-purple-50 text-purple-600 dark:bg-purple-900/20 dark:text-purple-400";
  }
  if (resource.includes("auth") || resource.includes("login")) {
    return "bg-amber-50 text-amber-600 dark:bg-amber-900/20 dark:text-amber-400";
  }
  return "bg-gray-50 text-gray-600 dark:bg-gray-900/20 dark:text-gray-400";
};

export const PermissionItem = ({
  permission,
  onToggleExpand,
  onRemove,
  onModifierChange,
}: PermissionItemProps) => {
  const iconColor = getPermissionIconColor(permission.resource);
  const hasModifier = !!permission.modifier;

  const handleModifierChange = useCallback(
    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
      onModifierChange(permission.resource, e.target.value || null);
    },
    [permission.resource, onModifierChange],
  );

  const handleClearModifier = useCallback(() => {
    onModifierChange(permission.resource, null);
  }, [permission.resource, onModifierChange]);

  return (
    <div className="group border-border bg-card flex flex-col rounded-lg border shadow-sm transition-all hover:shadow-md">
      <div className="flex items-center justify-between p-3">
        <div className="flex items-center gap-3">
          <div
            className={`flex size-6 items-center justify-center rounded-md ${iconColor}`}
          >
            <Shield className="size-3" />
          </div>
          <span className="text-foreground font-mono text-sm font-medium">
            {permission.resource}
          </span>
        </div>
        <div className="flex items-center gap-1">
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-sm"
                  className="size-7"
                  onClick={() => onToggleExpand(permission.resource)}
                >
                  {permission.isExpanded ? (
                    <EyeOffIcon className="size-4" />
                  ) : (
                    <Code className="size-4" />
                  )}
                </Button>
              </TooltipTrigger>
              <TooltipContent>
                {permission.isExpanded ? "Close Rule" : "Edit Rule"}
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-sm"
                  className="size-7"
                  onClick={() => onRemove(permission.resource)}
                >
                  <XCircle className="size-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent>Remove Permission</TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
      </div>

      {permission.isExpanded && (
        <div className="border-border bg-muted/10 animate-in fade-in slide-in-from-top-2 border-t p-3">
          <div className="bg-card border-border overflow-hidden rounded-md border shadow-sm">
            <div className="bg-muted/30 border-border flex items-center justify-between border-b px-3 py-1.5">
              <div className="flex items-center gap-2">
                <Code className="text-muted-foreground size-3.5" />
                <span className="text-muted-foreground font-mono text-[10px] tracking-wider uppercase">
                  Rule Definition
                </span>
              </div>
              {hasModifier && (
                <button
                  type="button"
                  className="text-muted-foreground hover:text-foreground text-[10px] transition-colors"
                  onClick={handleClearModifier}
                >
                  Clear
                </button>
              )}
            </div>
            <Textarea
              value={permission.modifier ?? ""}
              onChange={handleModifierChange}
              placeholder="// Enter custom rule logic..."
              className="min-h-[100px] resize-none rounded-none border-0 font-mono text-xs focus-visible:ring-0"
              spellCheck={false}
            />
          </div>
        </div>
      )}
    </div>
  );
};

import { useFastSchema } from "fastschema/react";
import { Check, ChevronRight, FolderOpen, Globe, Shield } from "lucide-react";
import { useCallback, useMemo, useState } from "react";

import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { FsDialog } from "@/components/fsui/fscommon/dialog";

import type { Resource } from "fastschema";
import type { ReactNode } from "react";

export interface ResourcePickerProps {
  trigger?: ReactNode;
  selectedResources: string[];
  onSelect: (resourceIds: string[]) => void;
}

// Check if a resource is public
const isPublicResource = (resource: Resource): boolean => {
  return resource.meta?.public === true;
};

// Recursive resource tree item
const ResourceTreeItem = ({
  resource,
  selectedIds,
  onToggle,
  level = 0,
  parentPath = "",
}: {
  resource: Resource;
  selectedIds: Set<string>;
  onToggle: (id: string) => void;
  level?: number;
  parentPath?: string;
}) => {
  const [isOpen, setIsOpen] = useState(level < 2);
  const isGroup = resource.group && resource.resources?.length;
  const isSelected = selectedIds.has(resource.id);
  const isPublic = isPublicResource(resource);
  const uniqueKey = parentPath ? `${parentPath}/${resource.id}` : resource.id;

  const selectedChildCount = useMemo(() => {
    if (!isGroup) return 0;
    const countSelected = (resources: Resource[]): number => {
      return resources.reduce((acc, r) => {
        if (r.group && r.resources?.length) {
          return acc + countSelected(r.resources);
        }
        return acc + (selectedIds.has(r.id) ? 1 : 0);
      }, 0);
    };
    return countSelected(resource.resources || []);
  }, [isGroup, selectedIds, resource.resources]);

  if (isGroup) {
    return (
      <Collapsible
        open={isOpen}
        onOpenChange={setIsOpen}
      >
        <CollapsibleTrigger asChild>
          <div
            role="button"
            tabIndex={0}
            onKeyDown={(e) => {
              if (e.key === "Enter" || e.key === " ") {
                setIsOpen(!isOpen);
              }
            }}
            className={cn(
              "hover:bg-accent flex cursor-pointer items-center gap-2 rounded-md px-2 py-1.5 text-sm transition-colors select-none",
              level > 0 && "ml-4",
            )}
          >
            <ChevronRight
              className={cn(
                "text-muted-foreground size-4 transition-transform",
                isOpen && "rotate-90",
              )}
            />
            <FolderOpen className="size-4 text-amber-500" />
            <span className="font-medium">{resource.name}</span>
            {selectedChildCount > 0 && (
              <span className="text-primary bg-primary/10 ml-auto rounded px-1.5 py-0.5 text-xs">
                {selectedChildCount} selected
              </span>
            )}
          </div>
        </CollapsibleTrigger>
        <CollapsibleContent>
          <div className="border-border ml-4 space-y-1 border-l pl-2">
            {resource.resources?.map((child) => (
              <ResourceTreeItem
                key={`${uniqueKey}/${child.id}`}
                resource={child}
                selectedIds={selectedIds}
                onToggle={onToggle}
                level={level + 1}
                parentPath={uniqueKey}
              />
            ))}
          </div>
        </CollapsibleContent>
      </Collapsible>
    );
  }

  if (isPublic) {
    return (
      <div
        className={cn(
          "flex w-full cursor-not-allowed items-center gap-2 rounded-md px-2 py-1.5 text-sm opacity-50",
          level > 0 && "ml-4",
        )}
        title="Public resources don't require permissions"
      >
        <Checkbox
          disabled
          checked={false}
          className="pointer-events-none"
        />
        <Globe className="size-4 text-green-500" />
        <span className="font-mono text-xs">{resource.id}</span>
        <span className="text-muted-foreground ml-auto text-xs">Public</span>
      </div>
    );
  }

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onToggle(resource.id)}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          onToggle(resource.id);
        }
      }}
      className={cn(
        "hover:bg-accent flex w-full cursor-pointer items-center gap-2 rounded-md px-2 py-1.5 text-sm transition-colors select-none",
        level > 0 && "ml-4",
        isSelected && "bg-primary/5",
      )}
    >
      <Checkbox
        checked={isSelected}
        onCheckedChange={() => onToggle(resource.id)}
        onClick={(e) => e.stopPropagation()}
      />
      <Shield className="size-4 text-blue-500" />
      <span className="font-mono text-xs">{resource.id}</span>
      {isSelected && <Check className="text-primary ml-auto size-4" />}
    </div>
  );
};

export const ResourcePicker = ({
  trigger,
  selectedResources,
  onSelect,
}: ResourcePickerProps) => {
  const { fastschema } = useFastSchema();
  const { appConfig } = fastschema.state();
  const [open, setOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [localSelected, setLocalSelected] = useState<Set<string>>(new Set());

  const handleOpenChange = useCallback((val: boolean) => {
    setOpen(val);
    if (!val) {
      setLocalSelected(new Set());
      setSearchQuery("");
    }
  }, []);

  const handleToggle = useCallback((id: string) => {
    setLocalSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, []);

  const handleConfirm = useCallback(() => {
    onSelect(Array.from(localSelected));
    setOpen(false);
    setLocalSelected(new Set());
    setSearchQuery("");
  }, [localSelected, onSelect]);

  const filterTree = useCallback(
    (rs: Resource[]): Resource[] => {
      const alreadySelected = new Set(selectedResources);

      const filterRecursive = (items: Resource[]): Resource[] => {
        return items
          .map((item) => {
            if (item.group && item.resources?.length) {
              const filteredChildren = filterRecursive(item.resources);
              if (filteredChildren.length > 0) {
                return { ...item, resources: filteredChildren };
              }
              return null;
            }
            if (alreadySelected.has(item.id)) {
              return null;
            }

            if (
              searchQuery &&
              !item.id.toLowerCase().includes(searchQuery.toLowerCase()) &&
              !item.name.toLowerCase().includes(searchQuery.toLowerCase())
            ) {
              return null;
            }
            return item;
          })
          .filter((item): item is Resource => item !== null);
      };

      return filterRecursive(rs);
    },
    [selectedResources, searchQuery],
  );

  const filteredTree = useMemo(
    () => filterTree(appConfig?.resources || []),
    [appConfig?.resources, filterTree],
  );

  return (
    <FsDialog
      open={open}
      onOpenChange={handleOpenChange}
      hideCloseButton
      trigger={trigger}
      title={
        <div className="flex items-center gap-2">
          <Input
            type="text"
            placeholder="Search resources..."
            name="search_resources"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      }
      actions={{
        left: (
          <div className="text-muted-foreground flex items-center text-sm">
            {localSelected.size} permission{localSelected.size === 1 ? "" : "s"}{" "}
            selected
          </div>
        ),
        right: (
          <Button
            type="button"
            onClick={handleConfirm}
            size="sm"
            disabled={localSelected.size === 0}
          >
            Add Selected
          </Button>
        ),
      }}
    >
      <div className="flex h-full flex-col">
        <ScrollArea className="flex-1">
          <div className="space-y-1 p-4">
            {filteredTree.length === 0 ? (
              <div className="text-muted-foreground py-8 text-center">
                {searchQuery
                  ? "No resources match your search."
                  : "All resources are already assigned."}
              </div>
            ) : (
              filteredTree.map((resource) => (
                <ResourceTreeItem
                  key={resource.id}
                  resource={resource}
                  selectedIds={localSelected}
                  onToggle={handleToggle}
                  parentPath=""
                />
              ))
            )}
          </div>
        </ScrollArea>
      </div>
    </FsDialog>
  );
};

