import type { User } from "fastschema";

export interface UserItemProps {
  user: User;
  onRemove?: (userId: number | string) => void;
}

const getInitials = (user: User): string => {
  const firstName = user.first_name || "";
  const lastName = user.last_name || "";
  const username = user.username || user.email || "";

  if (firstName || lastName) {
    return `${firstName.charAt(0)}${lastName.charAt(0)}`.toUpperCase();
  }
  return username.substring(0, 2).toUpperCase();
};

const getDisplayName = (user: User): string => {
  if (user.first_name || user.last_name) {
    return `${user.first_name || ""} ${user.last_name || ""}`.trim();
  }
  return user.username || user.email;
};

// Color palette for avatar backgrounds
const avatarColors = [
  "bg-indigo-100 text-indigo-600 dark:bg-indigo-900/30 dark:text-indigo-400",
  "bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400",
  "bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400",
  "bg-rose-100 text-rose-600 dark:bg-rose-900/30 dark:text-rose-400",
  "bg-purple-100 text-purple-600 dark:bg-purple-900/30 dark:text-purple-400",
  "bg-cyan-100 text-cyan-600 dark:bg-cyan-900/30 dark:text-cyan-400",
];

const getAvatarColor = (userId: number | string): string => {
  const id =
    typeof userId === "string" ? Number.parseInt(userId, 10) || 0 : userId;
  return avatarColors[id % avatarColors.length];
};

export const UserItem = ({ user, onRemove }: UserItemProps) => {
  const displayName = getDisplayName(user);
  const initials = getInitials(user);
  const avatarColor = getAvatarColor(user.id);

  return (
    <div className="hover:bg-muted/30 group flex items-center justify-between p-4 transition-colors">
      <div className="flex items-center gap-3">
        <Avatar className="size-9">
          {user.provider_profile_image && (
            <AvatarImage
              src={user.provider_profile_image}
              alt={displayName}
            />
          )}
          <AvatarFallback className={avatarColor}>{initials}</AvatarFallback>
        </Avatar>
        <div>
          <p className="text-sm leading-none font-medium">{displayName}</p>
          <p className="text-muted-foreground mt-1 text-xs">{user.email}</p>
        </div>
      </div>
      <div className="flex items-center gap-3">
        {user.active !== false && (
          <Badge
            variant="secondary"
            className="hidden sm:inline-flex"
          >
            Active
          </Badge>
        )}
        {onRemove && (
          <Button
            type="button"
            variant="ghost"
            size="icon-sm"
            className="text-muted-foreground hover:text-destructive opacity-0 transition-opacity group-hover:opacity-100 focus:opacity-100"
            title="Detach User"
            onClick={() => onRemove(user.id)}
          >
            <UserMinus className="size-4" />
          </Button>
        )}
      </div>
    </div>
  );
};

import { useForm } from "@tanstack/react-form";
import { roleCreateSchema } from "fastschema";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from "react";

import type { UseFormReturnOnChangeType } from "../fsform/fsform";
import type { Role, RoleCreateValues } from "fastschema";

// Permission with local state for UI
export interface PermissionState {
  resource: string;
  value: string;
  modifier?: string | null;
  isExpanded?: boolean;
}

// Context type
export interface RoleEditContextType {
  form: UseFormReturnOnChangeType;
  initialData?: Role;
  permissions: PermissionState[];
  isEditing: boolean;
  setPermissions: React.Dispatch<React.SetStateAction<PermissionState[]>>;
  addPermission: (resource: string) => void;
  removePermission: (resource: string) => void;
  updatePermissionModifier: (resource: string, modifier: string | null) => void;
  togglePermissionExpanded: (resource: string) => void;
}

export const RoleEditContext = createContext<RoleEditContextType | null>(null);

export const useRoleEditContext = () => {
  const context = useContext(RoleEditContext);
  if (!context) {
    throw new Error(
      "useRoleEditContext must be used within RoleEditContext.Provider",
    );
  }
  return context;
};

export const useRoleEditForm = () => {
  return useRoleEditContext().form;
};

export interface RoleEditProviderProps {
  initialData?: Role;
  onSubmit: (data: RoleCreateValues) => Promise<void> | void;
  children: ReactNode;
}

export const RoleEditProvider = ({
  initialData,
  onSubmit,
  children,
}: RoleEditProviderProps) => {
  const isEditing = Boolean(initialData?.id);

  const [permissions, setPermissions] = useState<PermissionState[]>(() => {
    if (!initialData?.permissions) return [];
    return initialData.permissions.map((p) => ({
      resource: p.resource,
      value: p.value,
      modifier: p.modifier,
      isExpanded: false,
    }));
  });

  const zodSchema = useMemo(() => roleCreateSchema, []);

  const defaultValues = useMemo<RoleCreateValues>(
    () => ({
      name: initialData?.name ?? "",
      description: initialData?.description ?? "",
      root: initialData?.root ?? false,
      rule: initialData?.rule ?? "",
      system: initialData?.system,
      users: undefined,
      permissions: permissions.map((p) => ({
        resource: p.resource,
        value: p.value,
        modifier: p.modifier,
      })),
    }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [initialData],
  );

  const form = useForm({
    defaultValues,
    validators: { onChange: zodSchema },
    onSubmit: async ({ value }) => {
      const payload: RoleCreateValues = {
        ...value,
        permissions: permissions.map((p) => ({
          resource: p.resource,
          value: p.value,
          modifier: p.modifier,
        })),
      };
      await onSubmit(payload);
    },
  });

  const addPermission = useCallback((resource: string) => {
    setPermissions((prev) => {
      if (prev.some((p) => p.resource === resource)) return prev;
      return [
        ...prev,
        { resource, value: "allow", modifier: null, isExpanded: false },
      ];
    });
  }, []);

  const removePermission = useCallback((resource: string) => {
    setPermissions((prev) => prev.filter((p) => p.resource !== resource));
  }, []);

  const updatePermissionModifier = useCallback(
    (resource: string, modifier: string | null) => {
      setPermissions((prev) =>
        prev.map((p) => (p.resource === resource ? { ...p, modifier } : p)),
      );
    },
    [],
  );

  const togglePermissionExpanded = useCallback((resource: string) => {
    setPermissions((prev) =>
      prev.map((p) =>
        p.resource === resource ? { ...p, isExpanded: !p.isExpanded } : p,
      ),
    );
  }, []);

  const contextValue = useMemo<RoleEditContextType>(
    () => ({
      form: form as unknown as UseFormReturnOnChangeType,
      initialData,
      permissions,
      isEditing,
      setPermissions,
      addPermission,
      removePermission,
      updatePermissionModifier,
      togglePermissionExpanded,
    }),
    [
      form,
      initialData,
      permissions,
      isEditing,
      addPermission,
      removePermission,
      updatePermissionModifier,
      togglePermissionExpanded,
    ],
  );

  return (
    <RoleEditContext.Provider value={contextValue}>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          form.handleSubmit();
        }}
      >
        {children}
      </form>
    </RoleEditContext.Provider>
  );
};

